I think it would be much better to separate the cases which expect a ValueError from those that do not.
The following could be used to test ValueErrors resulting from bad amounts:

```python
def make_lock_with_amount(amount):
    return Lock(amount, 1000, "a" * 32)

def make_mediated_transfer_with_amount(amount):
    return MediatedTransfer(0, 1, bin_addr, amount, bin_addr, "", lock(1), bin_addr, bin_addr, 0)

@pytest.mark.parametrize("amount", [-1, 2**256])
@pytest.mark.parametrize("make", [make_lock_with_amount, make_mediated_transfer_with_amount])
def test_lock_out_of_bounds(amount, make):
    with pytest.raises(ValueError):
        make(amount)
```

If you run that, it will fail with the following error:
```
_______________________________ test_lock_out_of_bounds[make1--1] ________________________________

amount = -1, make = <function make_mediated_transfer_with_amount at 0x7f7d96f7ec08>

    @pytest.mark.parametrize("amount", [-1, 2**256])
    @pytest.mark.parametrize("make", [make_lock_with_amount, make_mediated_transfer_with_amount])
    def test_lock_out_of_bounds(amount, make):
        with pytest.raises(ValueError):
>           make(amount)
E           Failed: DID NOT RAISE <type 'exceptions.ValueError'>

raiden/tests/unit/test_messages.py:170: Failed
```

